// Ingesta Places con PAGINACIÓN (hasta 3 páginas por búsqueda) + filtro geográfico.
// Hace los fetch desde el propio Code node (this.helpers.httpRequest), paginando con nextPageToken.
const API = $env.GOOGLE_PLACES_API_KEY;
const FIELD_MASK = 'places.id,places.displayName,places.internationalPhoneNumber,places.rating,places.userRatingCount,places.formattedAddress,nextPageToken';
const QUERIES = [
  ['plomero','plomero'], ['plomero','destapaciones'], ['plomero','plomero a domicilio'],
  ['electricista','electricista'], ['electricista','electricista matriculado'], ['electricista','instalaciones electricas'],
  ['gasista','gasista matriculado'], ['gasista','service de calderas'], ['gasista','plomero gasista'],
  ['cerrajero','cerrajero'], ['cerrajero','cerrajero 24 horas'],
  ['carpintero','carpintero'], ['carpintero','carpinteria'],
  ['pintor','pintor'], ['pintor','pintura de obra'],
  ['albanil','albanil'], ['albanil','construccion en seco durlock'],
  ['calefaccionista','calefaccion estufas salamandras'], ['calefaccionista','service de calefaccion'],
  ['jardinero','jardinero'], ['jardinero','poda de arboles'],
  ['cabanas','mantenimiento de cabanas'], ['cabanas','administracion de cabanas'],
  ['techista','techista zinguero'],
  ['herrero','herreria'],
  ['tecnico-pc','reparacion de computadoras'],
  ['flete','flete mudanzas'],
  ['limpieza','servicio de limpieza'],
];
const rows = [];
const seen = new Set();
async function search(q, pageToken) {
  const body = { textQuery: q + ' en San Martin de los Andes, Neuquen', regionCode: 'AR', languageCode: 'es', pageSize: 20 };
  if (pageToken) body.pageToken = pageToken;
  return await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://places.googleapis.com/v1/places:searchText',
    headers: { 'Content-Type': 'application/json', 'X-Goog-Api-Key': API, 'X-Goog-FieldMask': FIELD_MASK },
    body, json: true,
  });
}
for (const [rubro, q] of QUERIES) {
  let token = null;
  for (let page = 0; page < 3; page++) {
    let resp;
    try { resp = await search.call(this, q, token); } catch (e) { break; }
    const places = (resp && resp.places) ? resp.places : [];
    for (const p of places) {
      const digits = (p.internationalPhoneNumber || '').replace(/\D/g, '');
      if (!digits) continue;
      const phone = '+' + digits;
      if (!phone.startsWith('+54')) continue;
      const addr = p.formattedAddress || '';
      if (!/neuqu/i.test(addr) && !/8370/.test(addr)) continue;
      if (seen.has(phone)) continue;
      seen.add(phone);
      rows.push({
        name: (p.displayName && p.displayName.text) ? p.displayName.text : '',
        phone, rubro, ciudad: 'san-martin', source: 'google_places',
        rating_externo: (typeof p.rating === 'number') ? p.rating : null,
        reviews_externo: (typeof p.userRatingCount === 'number') ? p.userRatingCount : null,
        address: addr || null, notas: null,
      });
    }
    token = (resp && resp.nextPageToken) ? resp.nextPageToken : null;
    if (!token) break;
  }
}
return [{ json: { rows, count: rows.length } }];
